@Service
class GreetingService(private val repository: GreetingRepository) {
    fun message(): String = repository.findMessage()
}

class GreetingRepository {
    fun findMessage(): String = "hello from repo"
}

fun main() {
    val service = GreetingService(GreetingRepository())
    println(service.message())
}

class UserService {
    fun findName(id: Long): String = "user-$id"
}

class UserController(private val service: UserService) {
    fun show(id: Long): String = service.findName(id)
}

fun main() {
    val controller = UserController(UserService())
    println(controller.show(7))
}

