    println(member.id)
    println(member.name)
}

fun transfer(balance: Int, amount: Int): Int {
    val afterWithdraw = balance - amount
    val afterDeposit = afterWithdraw + amount
    return afterDeposit
}

fun main() {
    println(transfer(10, 3))
}

class TaxService {
    fun total(price: Int, rate: Double): Int = (price * (1 + rate)).toInt()
}

fun main() {
    val service = TaxService()
    println(service.total(100, 0.1))
}
